mapper.select:
SELECT p.panel_id, p.site_id, p.name, p.device_serial, p.m_no, p.installed_at, p.status, p.is_online, p.last_communicated_at, p.circuit_count, p.leak_ma_threshold, p.temp_threshold, p.humidity_threshold, p.overcurrent_threshold, p.gas_threshold, p.fire_threshold, p.created_at, p.updated_at, p.deleted_at FROM panel p INNER JOIN site s ON s.site_id = p.site_id WHERE p.deleted_at IS NULL AND s.deleted_at IS NULL
AND p.site_id = #{siteId}
AND p.status = #{status}
ORDER BY p.panel_id DESC

SELECT p.panel_id, p.site_id, p.name, p.device_serial, p.m_no, p.installed_at, p.status, p.is_online, p.last_communicated_at, p.circuit_count, p.leak_ma_threshold, p.temp_threshold, p.humidity_threshold, p.overcurrent_threshold, p.gas_threshold, p.fire_threshold, p.created_at, p.updated_at, p.deleted_at FROM panel p INNER JOIN site s ON s.site_id = p.site_id INNER JOIN user_site us ON us.site_id = s.site_id WHERE us.user_id = #{userId} AND us.deleted_at IS NULL AND p.deleted_at IS NULL AND s.deleted_at IS NULL
AND p.site_id = #{siteId}
AND p.status = #{status}
ORDER BY p.panel_id DESC

SELECT EXISTS(
    SELECT 1
    FROM panel
    WHERE device_serial = #{deviceSerial}
)

SELECT EXISTS(
    SELECT 1
    FROM panel
    WHERE device_serial = #{deviceSerial}
      AND panel_id != #{panelId}
)
